UPDATE fornecedores SET termos_fabricante = 'Esta Proposta Comercial e/ou Contrato contempla a oferta e/ou venda de produtos fabricados e comercializados através das empresas Springer e Climazon, pertencentes ao grupo Midea Carrier.
O fabricante dos produtos não se responsabiliza por quaisquer danos a terceiros e/ou danos indiretos em decorrência do uso, manuseio e instalação dos produtos, incluindo, mas não se limitando a lucros cessantes, sob qualquer fundamento ou teoria, perda da chance ou perda da oportunidade.
Sendo assim, o fabricante somente será responsável por eventuais danos materiais diretos, isto é, prejuízos diretos comprovadamente sofridos em decorrência de atos culposos e/ou dolosos de única e exclusiva responsabilidade do fabricante, sendo que o montante de responsabilidade em relação aos danos diretos, em nenhuma hipótese, poderá superar o valor total dos itens desta Proposta Comercial relacionados a Produtos de fabricação da Midea Carrier.' WHERE UPPER(nome_fantasia) LIKE '%MIDEA%';